sql:
SELECT src_size
FROM data_mappings
WHERE result > 50;

SELECT COUNT(*) AS active_parameters_count
FROM mapping_parameters
WHERE is_active = 1;

SELECT DISTINCT u.username
FROM users u
WHERE u.user_id IN (
  SELECT dm.user_id
  FROM data_mappings dm
);

SELECT user_id, COUNT(user_id) AS total_mapping_tasks
FROM data_mappings
GROUP BY user_id;

SELECT MIN(duration) AS shortest_duration, status
FROM mapping_logs
WHERE status = 'Failure';

SELECT AVG(duration) AS average_success_duration
FROM mapping_logs
WHERE status = 'Success';

SELECT COUNT(*) AS active_rules_count
FROM transformation_rules
WHERE user_id = 1 AND is_active = 1;

SELECT DISTINCT u.username
FROM users u
INNER JOIN data_mappings dm ON u.user_id = dm.user_id;

SELECT username
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM mapping_logs
);

SELECT event_description 
FROM mapping_events 
WHERE event_timestamp = '2023-10-01 10:10:00';

SELECT current_status, last_updated
FROM mapping_status
WHERE is_active = 1;
